import { setup, fromCallback, assign } from 'xstate';

type ResizeEvent = { type: 'RESIZE'; width: number; height: number };
type Events = ResizeEvent | { type: 'START' } | { type: 'STOP' };

const resizeListener = fromCallback<ResizeEvent>(({ sendBack }) => {
  const handler = () => {
    sendBack({
      type: 'RESIZE',
      width: window.innerWidth,
      height: window.innerHeight,
    });
  };
  window.addEventListener('resize', handler);
  return () => {
    window.removeEventListener('resize', handler);
  };
});

export const windowMachine = setup({
  types: {
    context: {} as { width: number; height: number },
    events: {} as Events,
  },
  actors: { resizeListener },
}).createMachine({
  id: 'window',
  context: { width: 0, height: 0 },
  initial: 'idle',
  states: {
    idle: {
      on: { START: 'watching' },
    },
    watching: {
      invoke: { src: 'resizeListener' },
      on: {
        RESIZE: {
          actions: assign({
            width: ({ event }) => event.width,
            height: ({ event }) => event.height,
          }),
        },
        STOP: 'idle',
      },
    },
  },
});
```

